import React from 'react';
import propTypes from 'prop-types';
import Link from 'next/link';

const AppLayout = ( {children }) => {
    return (
        <div>
            <div>
                <Link href="/"><a>about</a></Link>
            </div>
            {children}
        </div>
    )
};

AppLayout.propTypes = {
    children: propTypes.node.isRequired,
};

export default AppLayout;
